
alter table tb_image
    add period  varchar(255)  comment '解剖期限';
alter table fr_special
    add principal  bigint  comment '专题负责人';
update fr_special set principal = create_by where principal is null;

alter table fr_slide
    add viewers json null comment '已阅片用户';
alter table fr_special
    add is_permanent_del tinyint default 0 not null comment '是否永久删除';
alter table tb_organ
    change organ_id organ_code varchar(255) not null comment '脏器编码';
alter table tb_organ
    change species_code species_id varchar(100) not null comment '种属编码';
alter table tb_structure
    change organ_id organ_code varchar(100) null comment '脏器编码';






-- 创建用户设置表，包含（图像增强开关；阅片模式：1-列表模式、2-矩阵模式；默认截图尺寸:宽、高；滚轮灵敏度；拖拽灵敏度）

CREATE TABLE tb_user_setting
(
    user_settings_id          BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT '主键',
    user_id                   BIGINT  NOT NULL COMMENT '用户ID',
    enhance_switch            TINYINT NOT NULL DEFAULT 1 COMMENT '图像增强开关: 0-关闭, 1-开启',
    reading_mode              TINYINT NOT NULL DEFAULT 2 COMMENT '阅片模式: 1-列表模式, 2-矩阵模式',
    default_screenshot_width  INT     NOT NULL DEFAULT 800 COMMENT '默认截图尺寸-宽',
    default_screenshot_height INT     NOT NULL DEFAULT 600 COMMENT '默认截图尺寸-高',
    scroll_sensitivity        INT     NOT NULL DEFAULT 50 COMMENT '滚轮灵敏度',
    drag_sensitivity          INT     NOT NULL DEFAULT 50 COMMENT '拖拽灵敏度',
    create_by                 bigint  null comment '创建人id',
    create_time               datetime         default CURRENT_TIMESTAMP not null comment '创建时间',
    update_by                 bigint  null comment '更新人id',
    update_time               datetime         default CURRENT_TIMESTAMP not null comment '更新时间',
    UNIQUE INDEX idx_user_id (user_id)
) COMMENT = '用户设置表';

drop table if exists tb_organ_tag;
create table tb_organ_tag
(
    organ_tag_id             bigint auto_increment comment '主键id'
        primary key,
    species_id               varchar(100)                       null comment '种属id',
    organ_tag_code           varchar(255)                       null comment '脏器标签编码',
    organ_en                 varchar(255)                       null comment '英文名称',
    organ_name               varchar(255)                       null comment '脏器名称',
    abbreviation             varchar(255)                       null comment '标签简称',
    rgb                      varchar(255)                       null,
    chromatic_value          varchar(255)                       null comment '色值',
    organization_id          bigint                             null comment '机构',
    del_flag                 tinyint  default 0                 null comment '删除标志(0-正常，1-删除)',
    algorithm_support_status tinyint  default 1                 null comment '算法是否支持(0-支持，1-不支持)',
    create_by                bigint                             null comment '创建人id',
    create_time              datetime default CURRENT_TIMESTAMP not null comment '创建时间',
    update_by                bigint                             null comment '更新人id',
    update_time              datetime default CURRENT_TIMESTAMP not null comment '更新时间',
    index idx_species_id (species_id),
    index idx_organization_id (organization_id)
) collate utf8mb4_general_ci;



drop table if exists tb_structure_tag_set;
create table tb_structure_tag_set
(
    structure_tag_set_id      bigint auto_increment comment '标签集ID'
        primary key,
    structure_tag_set_name    varchar(100)                       null comment '标签集',
    structure_tag_set_name_en varchar(100)                       null comment '标签集英文',
    species_id                varchar(100)                             null comment '种属id',
    organ_code                varchar(255)                       null comment '脏器编码',
    organization_id           bigint   default 1                 null comment '组织机构ID',
    del_flag                  tinyint  default 0                 null comment '删除标志(0-正常，1-删除)',
    type                      tinyint  default 0                 null comment '标签类型 0-下拉筛选标签；1-自定义标签',
    create_by                 bigint                             null comment '创建人id',
    create_time               datetime default CURRENT_TIMESTAMP not null comment '创建时间',
    update_by                 bigint                             null comment '更新人id',
    update_time               datetime default CURRENT_TIMESTAMP not null comment '更新时间'
)
    collate utf8mb4_general_ci
    comment '结构标签集';
-- 种属id索引
alter table tb_structure_tag_set
    add index IDX_SPECIES_ID (species_id);
-- 组织机构ID
alter table tb_structure_tag_set
    add index IDX_ORGANIZATION_ID (organization_id);
-- 脏器编码索引
alter table tb_structure_tag_set
    add index IDX_ORGAN_CODE (organ_code);

drop table if exists tb_structure_tag;
create table tb_structure_tag
(
    structure_tag_id     bigint auto_increment comment '结构标签id'
        primary key,
    structure_tag_set_id bigint                             null comment '结构标签集ID',
    structure_tag_name   varchar(200)                       null comment '标注类别名称',
    structure_id         varchar(100)                       null comment '结构ID',
    rgb                  varchar(255)                       null comment '颜色的RGB值',
    hex                  varchar(200)                       null comment '颜色的HEX值',
    color                varchar(255)                       null comment '颜色名称(备用)',
    order_number         int                                null comment '图层顺序',
    organization_id      bigint                             null comment '组织机构ID',
    del_flag             tinyint  default 0                 null comment '删除标志(0-正常，1-删除)',
    create_by            bigint                             null comment '创建人id',
    create_time          datetime default CURRENT_TIMESTAMP not null comment '创建时间',
    update_by            bigint                             null comment '更新人id',
    update_time          datetime default CURRENT_TIMESTAMP not null comment '更新时间',
    group_inner_order    int                                null comment '组内标签顺序',
    type                 tinyint  default 0                 null comment '标签类型 0-下拉筛选标签；1-自定义标签'
)
    collate utf8mb4_general_ci
    comment '结构标签';
-- 结构标签集ID索引
create index idx_structure_tag_set_id
    on tb_structure_tag (structure_tag_set_id);
-- 组织机构ID
create index idx_organization_id
    on tb_structure_tag (organization_id);

truncate table tb_structure;







